function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ node: v, cost });
    }

    // Use a priority queue to perform Dijkstra-like search
    const pq = new MaxPriorityQueue({ priority: (x) => x.cost });
    pq.enqueue({ node: 0, cost: Infinity, minEdge: Infinity });

    // Keep track of the maximum minimum edge cost found
    let maxMinEdge = -1;

    while (pq.size() > 0) {
        const { node, cost, minEdge } = pq.dequeue();

        // If we reached the destination node
        if (node === n - 1) {
            maxMinEdge = Math.max(maxMinEdge, minEdge);
            continue;
        }

        // Skip if the current node is not online
        if (!online[node]) {
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const { node: neighbor, cost: edgeCost } of graph.get(node)) {
                // Skip if the neighbor is not online
                if (!online[neighbor]) {
                    continue;
                }

                // Calculate the new total cost and new minimum edge cost
                const newCost = cost + edgeCost;
                const newMinEdge = Math.min(minEdge, edgeCost);

                // If the new total cost is within the limit and the new minimum edge is better
                if (newCost <= k && newMinEdge > maxMinEdge) {
                    pq.enqueue({ node: neighbor, cost: newCost, minEdge: newMinEdge });
                }
            }
        }
    }

    return maxMinEdge === -1 ? -1 : maxMinEdge;
}

// Helper class for Max Priority Queue
class MaxPriorityQueue {
    constructor(options) {
        this.options = options;
        this.queue = [];
    }

    enqueue(item) {
        this.queue.push(item);
        this.queue.sort((a, b) => this.options.priority(b) - this.options.priority(a));
    }

    dequeue() {
        return this.queue.pop();
    }

    size() {
        return this.queue.length;
    }
}

